#!/usr/bin/env python3
from pathlib import Path
import base64

ROOT = Path.cwd()

if not (ROOT / "public").exists():
    raise FileNotFoundError("No encuentro public/. Ejecuta este script desde la raíz del proyecto.")

icons = {'public/icon-192.png': '', 'public/icon-512.png': '', 'public/apple-touch-icon.png': '', 'public/favicon-32.png': ''}

for rel, data in icons.items():
    path = ROOT / rel
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(base64.b64decode(data))

print("Icono actualizado a versión full-bleed: bordes pintados hasta el límite.")
print("Ejecuta: npm run build && git add public && git commit -m 'Make app icon full bleed' && git push && npx vercel --prod")
